        "\n",
        "        df = pd.DataFrame(resultados)\n",
        "\n",
        "        # Colunas adicionais para legibilidade\n",
        "        df[\"categoria\"]   = df[\"estrelas\"].map(MAPA_ESTRELAS)\n",
        "        df[\"score_pct\"]   = (df[\"score\"] * 100).round(2)\n",
